def longest_run_char(s):
    if not s:
        return ''

    max_len = 0
    current_char = s[0]
    current_len = 1

    for i in range(1, len(s)):
        if s[i] == current_char:
            current_len += 1
        else:
            if current_len >= max_len:
                max_len = current_len
                longest_char = current_char
            current_char = s[i]
            current_len = 1

    # Final check for the last character sequence
    if current_len >= max_len:
        longest_char = current_char

    return longest_char
